class Value:
    def __init__(self, data, parents=()):
        self.data=data; self.grad=0.0; self._parents=parents; self._back=lambda: None
    def __add__(self, o):
        o = o if isinstance(o, Value) else Value(o)
        out = Value(self.data+o.data, (self, o))
        def back(): self.grad += out.grad; o.grad += out.grad
        out._back = back; return out
    def __mul__(self, o):
        o = o if isinstance(o, Value) else Value(o)
        out = Value(self.data*o.data, (self, o))
        def back(): self.grad += o.data*out.grad; o.grad += self.data*out.grad
        out._back = back; return out
    def backward(self):
        topo=[]; seen=set()
        def build(v):
            if v not in seen:
                seen.add(v)
                for p in v._parents: build(p)
                topo.append(v)
        build(self); self.grad=1.0
        for v in reversed(topo): v._back()

a=Value(2.0); b=Value(3.0)
d=a*b + a
d.backward()
print(a.grad, b.grad)   # 4.0 2.0
```

`d = a·b + a`, so ∂d/∂a = b + 1 = 4 and ∂d/∂b = a = 2 — matched automatically. This ~25-line engine is micrograd; PyTorch is the same idea with tensors and more ops.
